  useEffect(() => { init(); }, []);

  async function init() {
    const params    = new URLSearchParams(window.location.search);
    const sessionId = params.get("session_id");
    let name        = "your";
    if (sessionId) {
      try {
        const res  = await fetch(`/api/get-session?id=${sessionId}`);
        const data = await res.json();
        if (data.firstName) name = data.firstName;
        setFirstName(name);
      } catch { /* non-fatal */ }
    }
    await generateAssessment(name);
  }

  async function generateAssessment(name: string) {
    setLoading(true);
    try {
      const ib_cost = sessionStorage.getItem("investment-boost-auditor_ib_cost") || "125000";
      const ib_type = sessionStorage.getItem("investment-boost-auditor_ib_type") || "machinery";
      const ib_available = sessionStorage.getItem("investment-boost-auditor_ib_available") || "true";
      const ib_status = sessionStorage.getItem("investment-boost-auditor_ib_status") || "clear";

      const prompt = `You are a UK tax expert. Write a personalised action plan for ${name !== "your" ? name : "this taxpayer"}.

Their data:
- Asset cost: ${ib_cost}\n- Asset type: ${ib_type}\n- Available from 22 May 2025: ${ib_available}\n- Status: ${ib_status}

Write a personalised, specific action plan. Use their name if provided. Reference their specific numbers. Be direct and actionable — not generic.

Respond ONLY with a valid JSON object. No markdown. No backticks. No preamble. Just JSON with these fields:
"status": "...", "boostDeduction": "...", "taxSaving": "...", "changeOfUseRisk": "...", "stageClaimOpportunity": "...", "disposalRecovery": "...", "actions": "...", "weekPlan": "...", "accountantQuestions": "..."

For array fields use actual arrays. For action items use objects with title, deadline, steps array.`;

      const res  = await fetch("https://api.anthropic.com/v1/messages", {
        method:  "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({
          model:      "claude-sonnet-4-20250514",
          max_tokens: 2000,
          messages:   [{ role: "user", content: prompt }],
        }),
      });
      const data   = await res.json();
      const text   = data.content?.[0]?.text ?? "";
      const clean  = text.replace(/```json|```/g, "").trim();
      setAssessment(JSON.parse(clean));
    } catch {
      // Fallback assessment if Claude API fails
      setAssessment(buildFallback(name));
    } finally {
      setLoading(false);
    }
  }

